import java.io.BufferedInputStream
private class FastScanner { private val input=BufferedInputStream(System.`in`); private val buffer=ByteArray(1 shl 16); private var len=0; private var ptr=0; private fun readByte():Int{ if(ptr>=len){ len=input.read(buffer); ptr=0; if(len<=0)return -1}; return buffer[ptr++].toInt()}; fun next():String{ var c=readByte(); while(c<=32&&c>=0)c=readByte(); val sb=StringBuilder(); while(c>32){ sb.append(c.toChar()); c=readByte()}; return sb.toString() } }
fun findItinerary(tickets: List<Pair<String,String>>): List<String> { val graph=HashMap<String, MutableList<String>>(); for((a,b) in tickets) graph.getOrPut(a){ mutableListOf() }.add(b); for(v in graph.values) v.sortDescending(); val route=mutableListOf<String>(); fun visit(a:String){ val dests=graph[a]; while(dests!=null && dests.isNotEmpty()){ val next=dests.removeAt(dests.size-1); visit(next) }; route.add(a) }; visit("JFK"); route.reverse(); return route }
fun fmt(r:List<String>)="["+r.joinToString(","){"\"$it\""}+"]"
fun main(){ val fs=FastScanner(); val t=fs.next().toInt(); val out=StringBuilder(); repeat(t){tc-> val m=fs.next().toInt(); val tickets=MutableList(m){ Pair(fs.next(), fs.next()) }; if(tc>0)out.append("\n\n"); out.append(fmt(findItinerary(tickets))) }; print(out.toString()) }
